var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>카페 이벤트의 신기원을 열다!</color>\\n익명의 제보자","JPN":"<color=#ffd34c>カフェイベントに革新！</color>\\n匿名記者","ENG":"[[","TWN":"<color=#ffd34c>開啟咖啡廳活動的新紀元！</color>\\n匿名評論者"},"stage":{"bg":"CITY_TWILIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"그라운드 원의 이색 테마 카페 스트레가에서 웨딩 시즌을 맞이하여 웨딩 이벤트를 개최했다.","JPN":"グラウンド・ワンの異色テーマカフェ「ストレガ」ではウェディングシーズンに合わせて、ウェディングイベントが開催された。","ENG":"The unique-themed Cafe Strega, in Ground One, has hosted a wedding-themed event in celebration of the marriage boom.","TWN":"G1一間風格獨特的咖啡廳史特雷加，配合結婚季舉辦一場特別的婚禮活動。"},"stage":{"bg":"CITY_TWILIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"오픈과 동시에 손님 모두 함께 참여할 수 있는 대단원의 연극이 시작되며, 종국의 결말로 치닫는다.","JPN":"オープンと同時に来店客全員が参加できる演劇が始まった。演劇は結末に向かって一気に駆け抜け、大団円で終わった。","ENG":"As the cafe opened its doors, a grand-scale play began, where all the customers could participate in as well. The play leads to a compelling finale and...","TWN":"進到咖啡廳後，便上演所有顧客都可以一起參與的大團圓戲劇，最後的結局也隨之而來。"},"stage":{"bg":"CITY_TWILIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_TWILIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"이후 카페 스트레가의 매출이 급격히 상승하여…….","JPN":"その後、カフェストレガの売上は急上昇し……","ENG":"This led to a significant increase in Cafe Strega's sales...","TWN":"這導致史特雷加咖啡廳的營業額大幅提升……"},"stage":{"bg":"CITY_TWILIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"매출 장표? 그래프가 마음에 드나 봐?","JPN":"売上台帳？　グラフが気に入ったみたいね。","ENG":"Is that the sales account? Seems like you're happy with the graph.","TWN":"這是營業統計？看來你對這個圖表很滿意呢？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"당연히 마음에 들지. 이렇게 예쁜 수직 상승선을 본 기억이 또 있나 싶을 정도야.","JPN":"当然だろう。これほど美しい右肩上がりの線がはたしてあるだろうかと思うくらいだ。","ENG":"Of course I do. I've never seen a more upward-oriented line before.","TWN":"當然滿意，我都想不起來我曾經看過如此美麗的曲線圖。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗. 손님들도 웨딩 디저트에 만족하고 돌아간 것 같아서 기분이 좋네.","JPN":"ふふっ。お客さんもウェディングデザートに満足してお帰りになったようで嬉しいわ。","ENG":"Ha ha. And it seems the customers were also satisfied with the wedding desserts. I'm glad.","TWN":"呵呵，我也很開心，因為客人都非常滿意婚禮甜點。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"앞으로도 종종 할까?","JPN":"これからも、たまにやろうかしら？","ENG":"Should we do this regularly?","TWN":"以後也多辦些活動吧？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그런 끔찍한 소리는 하지도 마.","JPN":"そんな恐ろしいこと言うな。","ENG":"Don't even think about it.","TWN":"你想嚇死我嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"드레스며 디저트며 온통 난리였던 거 생각하면…… 꿈에서 나올까 무섭다고.","JPN":"ドレスといい、デザートといい、すべてがカオス状態だったし……夢に出てきそうだ。","ENG":"The dresses, the desserts, the mess... I'm going to have nightmares.","TWN":"一想到婚紗、甜點、還有這些騷動……我作夢都會怕。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"혹시 악몽 꾸게 되면 말해!","JPN":"もし悪夢を見るようになったら言ってよ！","ENG":"Tell me if you do!","TWN":"作惡夢的話記得找我！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"마담 클로에 스타시커가 만든 악몽에 용한 부적을 사둔 게 있으니까!","JPN":"マダム・クロエ・スターシーカーの作った悪夢に効くお守りの買い置きがあるから！","ENG":"I bought some charms from Madam Chloe Starseeker, and they're supposed to be good for nightmares!","TWN":"我有跟克洛伊·尋星夫人買消災解厄的符咒！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그런 사이비 부적은 절대로 안 쓸 거야!","JPN":"そんなインチキのお守りなんか絶対に使わない！","ENG":"I'm never using those shady charms!","TWN":"我才不會用那種冒牌的符咒！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그보다 라우라…….","JPN":"そんなことより、ラウラ……","ENG":"Anyway, Laura...","TWN":"不過蘿拉……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>최초의 인형</color> 말하려는 거지?","JPN":"<color=#ffd34c>最初の人形</color>のことだろう？","ENG":"I know. The <color=#ffd34c>Original Puppet</color>, right?","TWN":"你是想說<color=#ffd34c>最初的人偶</color>的事吧？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"역시 느꼈나 보네.","JPN":"やっぱり感じたのね。","ENG":"You must've felt it too, then.","TWN":"你果然也有感覺到。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};